  ('pukao-6f0ba476-moex-00263', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於形成權之行使，何者應向法院聲請？', '["法定代理人對限制行為人訂立買賣契約之承認", "暴利行為之撤銷", "被脅迫而為買賣要約意思表示之撤銷", "買賣契約之解除"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00264', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列因買賣所為之意思表示，何者視為自始無效？', '["被脅迫而為買賣要約之意思表示", "真意保留之買賣承諾之意思表示", "經撤銷之被詐欺所為之買賣要約意思表示", "買賣承諾意思表示之錯誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00265', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '依民法設立之A社團法人，其董事甲於召集社員總會時，故意不通知乙、丙、丁三位社員，在乙、 丙未出席而丁雖出席卻未表示任何意見下，社員總會仍作成決議。下列敘述，何者正確？', '["該決議無效", "丁得於決議後3個月內請求法院撤銷該決議", "乙得於決議後3個月內起訴請求法院撤銷該決議", "丙得於決議後6個月內以意思表示向甲撤銷該決議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00266', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲對乙有A金錢債權，乙對丙有B金錢債權。就甲得否代位乙，行使乙對丙之B債權之情形， 下列敘述，何者錯誤？', '["須B債權清償期已屆至", "甲得代為受領丙對乙之清償，並主張優先受償", "甲須以自己之名義行使債權人代位權", "丙得以其得對乙主張抗辯之事由對抗甲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00267', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於死因贈與之敘述，何者正確？', '["因贈與人死亡而成立之贈與，稱為死因贈與", "性質上為有附款之贈與", "須經公證，始生效力", "受贈人因不法侵害贈與人致死者，該贈與人之繼承人得撤回之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00268', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲出借並交付乙新臺幣（下同）50萬元，依民法規定，下列敘述，何者正確？', '["若乙無法返還50萬元給甲，乙陷於給付不能", "以通用貨幣為借貸者，如返還時已失其通用效力，仍應以借貸時之貨幣種類返還之", "甲與乙約定有利息，如借貸期限為5年，利息應於每年年終支付之", "甲與乙成立使用借貸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
